import React, { useState, useEffect } from "react";
import { BrowserRouter, Route, Routes, Switch } from "react-router-dom"; // Adjusted import
import Menu from "./Menu";
import Login from "./Login"; 
import Register from "./Register"; // Assuming Register component exists
import logo from "/Users/noorhatem/Desktop/uni/semester 6/service oriented computing/quickbite/client/src/images/logo.png"; 
import { Box, CssBaseline, Typography, Button } from "@mui/material";
import { useNavigate } from "react-router-dom"; // New import

function App() {
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const navigate = useNavigate(); // useNavigate hook

  // Check if the user is already logged in (i.e., if JWT token exists)
  useEffect(() => {
    const token = localStorage.getItem("authToken");
    if (token) {
      setIsLoggedIn(true);
    }
  }, []);

  // Handle login state change
  const handleLogin = () => {
    setIsLoggedIn(true);
  };

  // Handle logout
  const handleLogout = () => {
    localStorage.removeItem("authToken");
    setIsLoggedIn(false);
    navigate("/login"); // Navigate to login after logout
  };

  return (
    <BrowserRouter>
      <Box
        display="flex"
        flexDirection="column"
        minHeight="100vh"
        style={{ backgroundColor: '#f1f1f1' }}
      >
        <CssBaseline />

        {/* Header with the logo */}
        <Box
          display="flex"
          justifyContent="flex-start"
          alignItems="center"
          height="80px"
          backgroundColor="#e2e2e2"
          paddingLeft="20px"
        >
          <img
            src={logo}
            alt="QuickBite logo"
            style={{
              width: '100px',
              height: 'auto',
            }}
          />
        </Box>

        {/* Conditional Rendering */}
        <Routes>
          <Route path="/login" element={<Login onLogin={handleLogin} />} />
          <Route path="/register" element={<Register />} /> {/* Register Route */}
          <Route
            path="/"
            element={isLoggedIn ? (
              <>
                <Menu />
                {/* Logout Button */}
                <Box textAlign="center" style={{ marginTop: '20px' }}>
                  <Button
                    onClick={handleLogout}
                    variant="contained"
                    color="secondary"
                    sx={{ backgroundColor: '#FF6F00', color: 'white', padding: '10px 20px' }}
                  >
                    Logout
                  </Button>
                </Box>
              </>
            ) : (
              <Login onLogin={handleLogin} />
            )}
          />
        </Routes>

        {/* Footer */}
        <footer
          style={{
            marginTop: 'auto',
            padding: '20px',
            backgroundColor: '#f1f1f1',
            textAlign: 'center',
          }}
        >
          <Typography variant="body2" color="textSecondary">
            © 2025 QuickBite. All rights reserved.
          </Typography>
        </footer>
      </Box>
    </BrowserRouter>
  );
}

export default App;
